const wfName = $json.workflow?.name || 'Unknown workflow';
const wfId = $json.workflow?.id || '';
const errorMsg = $json.execution?.error?.message || 'No error message';
const execId = $json.execution?.id || '';
const execUrl = $json.execution?.url || '';
const nodeName = $json.execution?.lastNodeExecuted || 'Unknown node';

// Always send errors to Dion (developer), never Julia
const chatId = '6216258938';
const botToken = $env.TELEGRAM_BOT_TOKEN;

const text = `\u26a0\ufe0f n8n ERROR in: ${wfName}\nNode: ${nodeName}\nError: ${errorMsg}\nExec: ${execUrl || execId}`;

await this.helpers.httpRequest({
  method: 'POST',
  url: `https://api.telegram.org/bot${botToken}/sendMessage`,
  body: { chat_id: chatId, text: text },
  json: true,
  timeout: 10000
});

return [{ json: { sent: true, chat_id: chatId } }];
